import{_ as a,c as t,o as e,b as m}from"./app.aaa68922.js";const c='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 7","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 7","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-06T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/7.md"}',o={},p=m('<div class="stanza"><a href="#s3.7" id="s3.7" class="num">3.7</a><div class="sans"><p>\u0924\u0926\u093E\u0939\u2014</p><blockquote><p><strong>\u092E\u094B\u0939\u091C\u092F\u093E\u0926\u0928\u0928\u094D\u0924\u093E\u092D\u094B\u0917\u093E\u0924\u094D\u0938\u0939\u091C\u0935\u093F\u0926\u094D\u092F\u093E\u091C\u092F\u0903\u0965\u096D\u0965</strong></p></blockquote><p>\u092E\u094B\u0939\u0938\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u0938\u092E\u0928\u093E\u0928\u094D\u0924\u092A\u093E\u0936\u093E\u0924\u094D\u092E\u0928\u094B \u092E\u093E\u092F\u093E\u092F\u093E \u091C\u092F\u093E\u0926\u092D\u093F\u092D\u0935\u093E\u0924\u094D\u0964 \u0915\u0940\u0926\u0943\u0936\u093E\u0926\u094D \u0905\u0928\u0928\u094D\u0924\u0903 \u0938\u0902\u0938\u094D\u0915\u093E\u0930\u092A\u094D\u0930\u0936\u092E\u092A\u0930\u094D\u092F\u0928\u094D\u0924 \u0906\u092D\u094B\u0917\u094B \u0935\u093F\u0938\u094D\u0924\u093E\u0930\u094B \u092F\u0938\u094D\u092F \u0924\u093E\u0926\u0943\u0936\u093E\u0924\u094D</p><blockquote><p>\u0935\u0947\u0926\u0928\u093E\u0928\u093E\u0926\u093F\u0927\u0930\u094D\u092E\u0938\u094D\u092F...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0928\u093E \u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0930\u0942\u092A\u093E\u092F\u093E\u0903 \u0938\u0939\u091C\u0935\u093F\u0926\u094D\u092F\u093E\u092F\u093E \u091C\u092F\u094B \u0932\u093E\u092D\u094B \u092D\u0935\u0924\u093F\u0964 \u0906\u0923\u0935\u094B\u092A\u093E\u092F\u0938\u094D\u092F\u093E\u092A\u093F \u0936\u093E\u0915\u094D\u0924\u094B\u092A\u093E\u092F\u092A\u0930\u094D\u092F\u0935\u0938\u093E\u0928\u093E\u0926\u093F\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u0924\u094D\u0935\u093E\u0924\u094D\u0964 \u0924\u0925\u093E \u091A \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0938\u092E\u0928\u093E\u0928\u094D\u0924\u0902 \u0935\u0930\u093E\u0930\u094B\u0939\u0947 \u092A\u093E\u0936\u091C\u093E\u0932\u092E\u0928\u0928\u094D\u0924\u0915\u092E\u094D\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>\u092A\u093E\u0936\u093E\u0935\u0932\u094B\u0915\u0928\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0932\u094B\u0915\u0928\u0902 \u0939\u093F \u092F\u0924\u094D\u0964<br> \u0906\u0924\u094D\u092E\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u093F\u0930\u094D\u092D\u0935\u0924\u094D\u092F\u0947\u0937\u093E \u0936\u093F\u0935\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u093F\u0938\u094D\u0924\u0924\u094B\u093D\u0928\u094D\u092F\u0925\u093E\u0965<br> \u0938\u093E\u0930\u094D\u0935\u091C\u094D\u091E\u094D\u092F\u093E\u0926\u093F\u0917\u0941\u0923\u093E \u092F\u0947\u093D\u0930\u094D\u0925\u093E \u0935\u094D\u092F\u093E\u092A\u0915\u093E\u0928\u094D\u092D\u093E\u0935\u092F\u0947\u0926\u094D\u092F\u0926\u093E\u0964<br> \u0936\u093F\u0935\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u093F\u0930\u094D\u092D\u0935\u0924\u094D\u092F\u0947\u0937\u093E \u091A\u0948\u0924\u0928\u094D\u092F\u0947 \u0939\u0947\u0924\u0941\u0930\u0942\u092A\u093F\u0923\u0940\u0965</p></blockquote><p>\u0907\u0924\u093F \u0917\u094D\u0930\u0928\u094D\u0925\u0947\u0928\u093E\u0924\u094D\u092E\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u094D\u092F\u0928\u094D\u0924\u0938\u094D\u092F \u092E\u094B\u0939\u0938\u094D\u092F \u091C\u092F\u093E\u0926\u0941\u0928\u094D\u092E\u0928\u093E\u0936\u093F\u0935\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u0903 \u0938\u0939\u091C\u0935\u093F\u0926\u094D\u092F\u093E\u092F\u093E\u0903 \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093F\u0930\u0941\u0915\u094D\u0924\u093E\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u0906\u0924\u094D\u092E\u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u0924\u0924\u0938\u094D\u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0935\u093F\u0926\u094D\u092F\u093E\u0924\u0924\u094D\u0924\u094D\u0935\u0947 \u0928\u093F\u092F\u094B\u091C\u092F\u0947\u0924\u094D\u0964<br> \u0909\u0928\u094D\u092E\u0928\u093E \u0938\u093E \u0924\u0941 \u0935\u093F\u091C\u094D\u091E\u0947\u092F\u093E \u092E\u0928\u0903 \u0938\u0919\u094D\u0915\u0932\u094D\u092A \u0909\u091A\u094D\u092F\u0924\u0947\u0965<br> \u0938\u0919\u094D\u0915\u0932\u094D\u092A\u0903 \u0915\u094D\u0930\u092E\u0924\u094B \u091C\u094D\u091E\u093E\u0928\u092E\u0941\u0928\u094D\u092E\u0928\u0902 \u092F\u0941\u0917\u092A\u0924\u094D\u0938\u094D\u0925\u093F\u0924\u092E\u094D\u0964<br> \u0924\u0938\u094D\u092E\u093E\u0924\u094D\u0938\u093E \u0924\u0941 \u092A\u0930\u093E \u0935\u093F\u0926\u094D\u092F\u093E \u092F\u0938\u094D\u092E\u093E\u0926\u0928\u094D\u092F\u093E \u0928 \u0935\u093F\u0926\u094D\u092F\u0924\u0947\u0964<br> \u0935\u093F\u0928\u094D\u0926\u0924\u0947 \u0939\u094D\u092F\u0924\u094D\u0930 \u092F\u0941\u0917\u092A\u0924\u094D\u0938\u093E\u0930\u094D\u0935\u091C\u094D\u091E\u094D\u092F\u093E\u0926\u093F\u0917\u0941\u0923\u093E\u0928\u094D\u092A\u0930\u093E\u0928\u094D\u0965<br> \u0935\u0947\u0926\u0928\u093E\u0928\u093E\u0926\u093F\u0927\u0930\u094D\u092E\u0938\u094D\u092F \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u092C\u094B\u0927\u0928\u093E\u0964<br> \u0935\u0930\u094D\u091C\u0928\u093E\u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u0947 \u0924\u0938\u094D\u092E\u093E\u0926\u094D\u0935\u093F\u0926\u094D\u092F\u0947\u0924\u093F \u0938\u094B\u091A\u094D\u092F\u0924\u0947\u0965<br> \u0924\u0924\u094D\u0930\u0938\u094D\u0925\u094B \u0935\u094D\u092F\u091E\u094D\u091C\u092F\u0947\u0924\u094D\u0924\u0947\u091C\u0903 \u092A\u0930\u0902 \u092A\u0930\u092E\u0915\u093E\u0930\u0923\u092E\u094D\u0964</p></blockquote><p>\u0907\u0924\u093F\u0965\u096D\u0965</p></div><hr><div class="trans"><p>Tad\u0101ha\u2014</p><blockquote><p><strong>Mohajay\u0101danant\u0101bhog\u0101tsahajavidy\u0101jaya\u1E25||7||</strong></p></blockquote><p>Mohasy\u0101khy\u0101ty\u0101tmakasaman\u0101ntap\u0101\u015B\u0101tmano m\u0101y\u0101y\u0101 jay\u0101dabhibhav\u0101t| K\u012Bd\u1E5B\u015B\u0101d ananta\u1E25 sa\u1E41sk\u0101rapra\u015Bamaparyanta \u0101bhogo vist\u0101ro yasya t\u0101d\u1E5B\u015B\u0101t</p><blockquote><p>Vedan\u0101n\u0101didharmasya...|</p></blockquote><p>ity\u0101din\u0101 nir\u016Bpitar\u016Bp\u0101y\u0101\u1E25 sahajavidy\u0101y\u0101 jayo l\u0101bho bhavati| \u0100\u1E47avop\u0101yasy\u0101pi \u015B\u0101ktop\u0101yaparyavas\u0101n\u0101dityuktatv\u0101t| Tath\u0101 ca \u015Br\u012Bsvacchande</p><blockquote><p>Saman\u0101nta\u1E41 var\u0101rohe p\u0101\u015Baj\u0101lamanantakam|</p></blockquote><p>ityupakramya</p><blockquote><p>P\u0101\u015B\u0101valokana\u1E41 tyaktv\u0101 svar\u016Bp\u0101lokana\u1E41 hi yat|<br> \u0100tmavy\u0101ptirbhavatye\u1E63\u0101 \u015Bivavy\u0101ptistato&#39;nyath\u0101||<br> S\u0101rvaj\xF1y\u0101digu\u1E47\u0101 ye&#39;rth\u0101 vy\u0101pak\u0101nbh\u0101vayedyad\u0101|<br> \u015Aivavy\u0101ptirbhavatye\u1E63\u0101 caitanye hetur\u016Bpi\u1E47\u012B||</p></blockquote><p>iti granthen\u0101tmavy\u0101ptyantasya mohasya jay\u0101dunman\u0101\u015Bivavy\u0101pty\u0101tmana\u1E25 sahajavidy\u0101y\u0101\u1E25 pr\u0101ptirukt\u0101| Yadukta\u1E41 tatraiva</p><blockquote><p>\u0100tmatattva\u1E41 tatastyaktv\u0101 vidy\u0101tattve niyojayet|<br> Unman\u0101 s\u0101 tu vij\xF1ey\u0101 mana\u1E25 sa\u1E45kalpa ucyate||<br> Sa\u1E45kalpa\u1E25 kramato j\xF1\u0101namunmana\u1E41 yugapatsthitam||<br> Tasm\u0101ts\u0101 tu par\u0101 vidy\u0101 yasm\u0101dany\u0101 na vidyate|<br> Vindate hyatra yugapats\u0101rvaj\xF1y\u0101digu\u1E47\u0101npar\u0101n||<br> Vedan\u0101n\u0101didharmasya param\u0101tmatvabodhan\u0101|<br> Varjan\u0101param\u0101tmatve tasm\u0101dvidyeti socyate||<br> Tatrastho vya\xF1jayetteja\u1E25 para\u1E41 paramak\u0101ra\u1E47am|</p></blockquote><p>iti||7||</p></div><hr><p>[\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em> \u0442\u0430\u043A --\u0442.\u0435. \u0447\u0442\u043E-- <em>(tad)</em> [\u043A\u043E\u0433\u0434\u0430 Moha, \u0438\u043B\u0438 \u0417\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u0432\u0435\u0440\u0436\u0435\u043D\u043E]\u2014</p><blockquote><p><strong>[Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442] \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u043B\u0430\u0434\u0435\u043D\u0438\u044F <em>(jaya\u1E25)</em> \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(sahaja)</em> \u0417\u043D\u0430\u043D\u0438\u0435\u043C <em>(vidy\u0101)</em> \u0447\u0435\u0440\u0435\u0437 \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435 \u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u0435 <em>(jay\u0101t anant\u0101bhog\u0101t)</em> M\u0101y\u0101, \u0438\u043B\u0438 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(moha)</em>||7||</strong></p></blockquote><p>Mohajay\u0101t <em>(mohasya... jay\u0101t)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u044F <em>(abhibhav\u0101t)</em> M\u0101y\u0101 <em>(m\u0101y\u0101y\u0101\u1E25)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 --\u0442.\u0435. M\u0101y\u0101-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(\u0101tmana\u1E25)</em> [\u0431\u044B\u0442\u044C] \u043F\u0435\u0442\u043B\u0435\u0439 <em>(p\u0101\u015Ba)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(anta)</em> \u0432 Saman\u0101 <em>(saman\u0101)</em> [\u0438] \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(\u0101tmaka)</em> \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(akhy\u0101ti)</em><sup>1</sup>|</p><p>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u0430\u043A\u043E\u0433\u043E \u0432\u0438\u0434\u0430 [\u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u044F] <em>(k\u012Bd\u1E5B\u015B\u0101t)</em>? \u0427\u0435\u0440\u0435\u0437 \u0442\u043E\u0442 \u0432\u0438\u0434 [\u0437\u0430\u0432\u043E\u0435\u0432\u0430\u043D\u0438\u044F] <em>(t\u0101d\u1E5B\u015B\u0101t)</em>, \u0447\u044C\u0435 <em>(yasya)</em> \u0101bhoga <em>(\u0101bhoga\u1E25)</em> , [\u0438\u043B\u0438] \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 <em>(vist\u0101ra\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u044B\u043C (ananta) --\u0442.\u0435. \u0431\u0435\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u044C\u043D\u044B\u043C-- <em>(ananta\u1E25)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0440\u043E\u0441\u0442\u0438\u0440\u0430\u0435\u0442\u0441\u044F \u0434\u043E <em>(anta\u1E25)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(pra\u015Bama)</em> \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u044B\u0445 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u0439/\u043E\u0442\u043F\u0435\u0447\u0430\u0442\u043A\u043E\u0432 [\u043F\u0440\u043E\u0448\u043B\u044B\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439] <em>(sa\u1E41sk\u0101ra)</em><sup>2</sup>|</p><p>[\u0418\u0442\u0430\u043A,] \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0435 \u0432\u043B\u0430\u0434\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u0435 <em>(jaya\u1E25)</em>, [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] \u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u0435 <em>(l\u0101bha\u1E25)</em> \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0417\u043D\u0430\u043D\u0438\u0435\u043C <em>(sahaja-vidy\u0101y\u0101\u1E25)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bp\u0101y\u0101\u1E25)</em> \u043E\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u043E\u0432\u0430\u043D\u0430 <em>(nir\u016Bpita)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442\u0435 Svacchandatantra:]</p><blockquote><p>&quot;\u041E\u043D\u0430 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 <em>(vedan\u0101)</em> \u0431\u0435\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0445 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A [\u0413\u043E\u0441\u043F\u043E\u0434\u0430] --\u0442.\u0435. \u0415\u0433\u043E \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B, \u0438\u043B\u0438 Sv\u0101tantrya-- <em>(an\u0101di-dharmasya)</em>, \u0438 \u0442.\u0434. <em>(iti \u0101din\u0101)</em><sup>3</sup>&quot;||<br> [\u0421\u043C. IV, 396 \u0432 Svacchandatantra]</p></blockquote><p>[\u041E \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0438 \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0417\u043D\u0430\u043D\u0438\u0439 \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E] \u0434\u0430\u0436\u0435 <em>(api)</em> [\u0432 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435] \u0100\u1E47avop\u0101ya <em>(\u0101\u1E47ava-up\u0101yasya)</em> \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0430 --\u0442.\u0435. \u0100\u1E47avop\u0101ya-- \u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(iti uktatv\u0101t)</em>, \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(paryavas\u0101n\u0101t)</em> \u0432 \u015A\u0101ktop\u0101ya <em>(\u015B\u0101kta-up\u0101ya)</em>|</p><p>\u0422\u0430\u043A <em>(tath\u0101 ca)</em>, \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(upakramya)</em>:</p><blockquote><p>&quot;\u041E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u0430\u044F <em>(vara-\u0101rohe)</em>!, [\u0438\u043C\u0435\u0435\u0442\u0441\u044F] \u043D\u0435\u0441\u043A\u043E\u043D\u0447\u0430\u0435\u043C\u0430\u044F <em>(anantakam)</em> \u0441\u0435\u0442\u044C <em>(j\u0101lam)</em> \u043F\u0435\u0442\u0435\u043B\u044C <em>(p\u0101\u015Ba)</em>, \u0434\u043E\u0445\u043E\u0434\u044F\u0449\u0430\u044F \u0434\u043E <em>(antam)</em> Saman\u0101 <em>(saman\u0101... iti)</em>&quot;||<br> [\u0421\u043C. IV, 432 \u0432 Svacchandatantra]</p></blockquote><p>[\u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0441:]</p><blockquote><p>&quot;\u041F\u043E\u0441\u043B\u0435 \u043E\u0442\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u043D\u0438\u044F <em>(tyaktv\u0101)</em> \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0441\u0435\u0431\u044F <em>(avalokanam)</em> \u0441 \u043F\u0435\u0442\u043B\u0435\u0439 --\u0442.\u0435. \u043E\u043A\u043E\u0432-- <em>(p\u0101\u015Ba)</em>, [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u044D\u0442\u043E\u0442 <em>(hi yad)</em> \u0430\u043A\u0442 \u0432\u0438\u0434\u0435\u043D\u0438\u044F <em>(\u0101lokanam)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em>. \u042D\u0442\u043E <em>(e\u1E63\u0101)</em> \u0435\u0441\u0442\u044C <em>(bhavati)</em> \u0100tmavy\u0101pti --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0432 \u0421\u0430\u043C\u043E\u0441\u0442\u044C-- <em>(\u0101tma-vy\u0101pti\u1E25)</em><sup>4</sup></p></blockquote><p>. \u015Aivavy\u0101pti --\u0442.\u0435. \u0441\u043B\u0438\u044F\u043D\u0438\u0435 \u0441 \u015Aiva-- <em>(\u015Biva-vy\u0101pti\u1E25)</em> [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(anyath\u0101)</em> \u043E\u0442 \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u043E\u0442 \u0100tmavy\u0101pti-- <em>(tatas)</em>. \u0410rtha-s --\u0436\u0435\u043B\u0430\u0435\u043C\u044B\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B-- <em>(ye arth\u0101\u1E25)</em> [\u2014 \u044D\u0442\u043E] \u0442\u0435, \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430\u043C\u0438 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 <em>(gu\u1E47\u0101\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435 <em>(s\u0101rvaj\xF1ya)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>. \u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [Yog\u012B] \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442, [\u0432\u043D\u0443\u0442\u0440\u0438 \u0441\u0435\u0431\u044F \u044D\u0442\u0438 artha-s] <em>(bh\u0101vayet)</em> \u043A\u0430\u043A \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0435 [\u0432\u0441\u0435 \u0441\u0443\u0449\u0435\u0435] <em>(vy\u0101pak\u0101n)</em>, \u044D\u0442\u043E <em>(e\u1E63\u0101)</em> \u0435\u0441\u0442\u044C <em>(bhavati)</em> \u015Aivavy\u0101pti <em>(\u015Biva-vy\u0101pti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439, \u0438\u043B\u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(hetu-r\u016Bpi\u1E47\u012B)</em> \u0434\u043B\u044F [\u0441\u0442\u0438\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F] Caitanya <em>(caitanye... iti)</em> [\u0432 Sv\u0101tantrya, \u0438\u043B\u0438 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0443\u044E \u0421\u0432\u043E\u0431\u043E\u0434\u0443 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430]<sup>5</sup>&quot;|| [\u0421\u043C. IV, 434-435 \u0432 Svacchandatantra]</p><p>[\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C,] \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043A\u043D\u0438\u0433\u0435 --\u0442.\u0435. Svacchandatantra-- <em>(granthena)</em>, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(ukt\u0101)</em>, \u0447\u0442\u043E [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u0435 <em>(pr\u0101pti\u1E25)</em> Sahajavidy\u0101 --\u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0417\u043D\u0430\u043D\u0438\u0435\u043C-- <em>(sahaja-vidy\u0101y\u0101\u1E25)</em>, \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E <em>(\u0101tmana\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u015Aivavy\u0101pti --\u0441\u043B\u0438\u044F\u043D\u0438\u0435 \u0441 \u015Aiva-- <em>(\u015Biva-vy\u0101pti)</em>, [\u0432\u0435\u0434\u0443\u0449\u0435\u0433\u043E \u043A] Unman\u0101 --\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u015Aiva, \u043F\u043E\u043B\u043D\u043E\u043C\u0443 \u0415\u0433\u043E \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B-- <em>(unman\u0101)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u044E <em>(jay\u0101t)</em> Moha, \u0438\u043B\u0438 M\u0101y\u0101 <em>(mohasya)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F \u0434\u043E <em>(antasya)</em> \u0100tmavy\u0101pti, \u0438\u043B\u0438 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0432 \u0421\u0430\u043C\u043E\u0441\u0442\u044C <em>(\u0101tma-vy\u0101pti)</em> --\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, M\u0101y\u0101 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0100tmavy\u0101pti--|</p><p>\u0422\u0430\u043A <em>(yad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0442\u043E\u043C \u0441\u0430\u043C\u043E\u043C [\u041F\u0438\u0441\u0430\u043D\u0438\u0438] <em>(tatra eva)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0432 Svacchandatantra--:</p><blockquote><p>&quot;\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(tatas)</em>, \u0447\u0435\u0440\u0435\u0437 \u043E\u0442\u043A\u0430\u0437 \u043E\u0442 <em>(tyaktv\u0101)</em> \u0100tmatattva --\u0431\u0443\u043A\u0432. \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u0442.\u0435. \u0100tmavy\u0101pti, \u0438\u043B\u0438 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0432 \u0421\u0430\u043C\u043E\u0441\u0442\u044C-- <em>(\u0101tma-tattva)</em>, [Yog\u012B] \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u0432\u044F\u0437\u0430\u0442\u044C [\u0441\u0435\u0431\u044F] <em>(niyojayet)</em> \u0441 Vidy\u0101tattva --\u0431\u0443\u043A\u0432. \u0441 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F-- <em>(vidy\u0101-tattve)</em>. \u042D\u0442\u043E [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 Vidy\u0101] <em>(s\u0101)</em> \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E <em>(vij\xF1ey\u0101)</em> \u043A\u0430\u043A Unman\u0101 --\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u015Aiva-- <em>(unman\u0101)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(tu)</em>. Manas --\u0442.\u0435. \u0443\u043C, \u0438\u043B\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0443\u043C-- <em>(manas)</em> \u043A\u0430\u043A \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F, \u2014 \u044D\u0442\u043E <em>(ucyate)</em> \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u0435 <em>(sa\u1E45kalpa\u1E25)</em>. [\u0422\u0430\u043A\u043E\u0435] \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u0435 <em>(sa\u1E45kalpa\u1E25)</em> [\u0435\u0441\u0442\u044C] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em>, [\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u043C\u043E\u0435] \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(kramatas)</em>, \u0442\u043E\u0433\u0434\u0430 \u043A\u0430\u043A Unman\u0101 --\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0435 \u043E\u0442 \u0443\u043C\u0430-- <em>(unmanam)</em> [\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442\u0441\u044F] \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(yugapad)</em> [\u0438 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C --\u0442.\u0435. \u0432\u0435\u0447\u043D\u044B\u043C-- <em>(sthitam)</em>. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tasm\u0101t)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yasm\u0101t)</em> \u043D\u0435\u0442 <em>(na vidyate)</em> \u0434\u0440\u0443\u0433\u043E\u0433\u043E <em>(any\u0101)</em>, \u041E\u043D\u0430 <em>(s\u0101)</em> \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(tu)</em> \u0412\u044B\u0441\u0448\u0435\u0439 <em>(par\u0101)</em> Vidy\u0101 --\u0442.\u0435. \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0417\u043D\u0430\u043D\u0438\u0435\u043C-- <em>(vidy\u0101)</em>. \u0422\u043E\u0433\u0434\u0430 --\u043A\u043E\u0433\u0434\u0430 \u0412\u044B\u0441\u0448\u0430\u044F Vidy\u0101 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F-- <em>(atra)</em>, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(ca)</em>, [Yog\u012B] \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 <em>(vindate)</em> \u0432\u044B\u0441\u0448\u0438\u0435 <em>(par\u0101n)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 <em>(gu\u1E47\u0101n)</em> \u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(s\u0101rvaj\xF1ya)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u043E\u0434\u043D\u043E\u043C\u043E\u043C\u0435\u043D\u0442\u043D\u043E <em>(yugapad)</em>. \u0422\u0430\u043A \u043A\u0430\u043A [1] \u041E\u043D\u0430 \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 <em>(vedan\u0101)</em> \u0431\u0435\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0445 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A [\u0413\u043E\u0441\u043F\u043E\u0434\u0430] --\u0442.\u0435. \u0415\u0433\u043E \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B, \u0438\u043B\u0438 Sv\u0101tantrya-- <em>(an\u0101di-dharmasya)</em>; [2] \u043F\u043E\u0431\u0443\u0436\u0434\u0430\u0435\u0442 \u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F/\u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F <em>(bodhan\u0101)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(parama-\u0101tmatva)</em>; [\u0438][3] \u0443\u0441\u0442\u0440\u0430\u043D\u044F\u0435\u0442 \u0442\u043E <em>(varjan\u0101)</em>, \u0447\u0442\u043E \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(a-parama-\u0101tmatve)</em>; \u0432 \u0441\u0438\u043B\u0443 [\u0432\u0441\u0435\u0433\u043E] \u044D\u0442\u043E\u0433\u043E <em>(tasm\u0101t)</em> \u041E\u043D\u0430 <em>(s\u0101)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(ucyate)</em> &#39;Vidy\u0101&#39; <em>(vidy\u0101 iti)</em>. \u0423\u043A\u043E\u0440\u0435\u043D\u0438\u0432\u0448\u0438\u0441\u044C <em>(stha\u1E25)</em> \u0442\u0430\u043C --\u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u043C \u043E\u0442 \u0443\u043C\u0430 (unman\u0101), \u0442.\u0435. \u0432 \u0412\u044B\u0441\u0448\u0435\u043C \u042F-- <em>(tatra)</em>, \u043E\u043D \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 <em>(vya\xF1jayet)</em> \u0412\u044B\u0441\u0448\u0438\u0439 <em>(param)</em> \u0421\u0432\u0435\u0442 <em>(tejas)</em> --\u0431\u0443\u043A\u0432. \u0421\u0432\u0435\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u0430--, \u0412\u044B\u0441\u0448\u0443\u044E <em>(parama)</em> \u041F\u0440\u0438\u0447\u0438\u043D\u0443 <em>(k\u0101ra\u1E47am... iti)</em>&quot;||<br> [\u0421\u043C. IV, 393-397 \u0432 Svacchandatantra]</p></blockquote><p>||7||</p><hr><ol><li><p>Saman\u0101 \u2014 \u044D\u0442\u043E \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0430\u044F \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u043C\u044B\u0441\u043B\u044C \u043E\u0442 \u015B\u016Bnya, \u0438\u043B\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043F\u0443\u0441\u0442\u043E\u0442\u044B, \u0434\u043E \u0442\u0430\u0442\u0442\u0432\u044B 36.</p></li><li><p>\u0411\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u0435 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435, \u0442.\u0435. \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435. \u041E\u0442\u0441\u044E\u0434\u0430 \u043C\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435: jay\u0101t anant\u0101bhog\u0101t - \u0447\u0435\u0440\u0435\u0437 \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435 \u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u0435. Sa\u1E41sk\u0101ra-s \u2014 \u044D\u0442\u043E \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u044B\u0435 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F \u043E\u0442 \u043F\u0440\u043E\u0448\u043B\u044B\u0445 karma-s, \u0438\u043B\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u0421\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0432\u0441\u0435\u0445 \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u044B\u0445 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u0439 \u0435\u0441\u0442\u044C \u044D\u0433\u043E. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043A\u043E\u0433\u0434\u0430 \u0442\u0430\u043A\u0430\u044F \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0443\u0434\u0430\u043B\u044F\u0435\u0442\u0441\u044F, \u0432\u0430\u0448\u0435\u0439 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u043A\u043E\u043D\u0435\u0446, \u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u043E\u0434\u0438\u043D \u0432 \u0444\u043E\u0440\u043C\u0435 \u0432\u0430\u0448\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 (\u0412\u0430\u0441 \u0421\u0430\u043C\u0438\u0445!).</p></li><li><p>\u041C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u0432\u0441\u044E \u0441\u0442\u0440\u043E\u0444\u0443 \u0440\u0430\u043D\u0435\u0435, \u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 21 \u041F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u0435\u0435 \u043E\u043F\u044F\u0442\u044C \u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043A \u044D\u0442\u043E\u043C\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443.</p></li><li><p>\u042D\u0442\u043E \u043F\u0435\u0440\u0432\u0430\u044F \u0441\u0442\u0430\u0434\u0438\u044F \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0422\u0440\u0438\u043A\u0435. \u041E\u043A\u043E\u0432\u044B \u2014 \u044D\u0442\u043E \u0432\u0441\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A Ka\xF1cuka-s, \u044D\u0433\u043E, \u0443\u043C, \u0442\u0435\u043B\u043E \u0438 \u0442.\u0434. \u041A\u043E\u0433\u0434\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0441\u0432\u043E\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u042F, \u0438\u043B\u0438 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043A\u0430\u043A \u0442\u043E\u043B\u044C\u043A\u043E J\xF1\u0101na, \u0438\u043B\u0438 \u0417\u043D\u0430\u043D\u0438\u0435, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0435 \u0432\u0441\u044F\u043A\u043E\u0439 Kriy\u0101, \u0438\u043B\u0438 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u044D\u0442\u043E \u0435\u0441\u0442\u044C \u0100tmavy\u0101pti, \u0438\u043B\u0438 \u043F\u0440\u0438\u0441\u0443\u0449\u0435\u0435 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 (\u0431\u0443\u043A\u0432. \u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u043E\u0435 \u0438 \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u043E\u0435 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 \u0432 Yog\u012B). \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0421\u0430\u043C\u043E\u0441\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044C, \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043E\u0442 \u0432\u0441\u0435\u0433\u043E \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E. \u0422\u0430\u043A \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u0432\u044B\u0440\u0430\u0436\u0430\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0432 Svacchandatantra: &quot;... \u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u092A\u093E\u0938\u094B\u0924\u094D\u0924\u0940\u0930\u094D\u0923\u091A\u093F\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u0924\u094D\u0935\u0902 \u092F\u0926\u094D... &quot; - &quot;... svar\u016Bpa\u1E41 p\u0101sott\u012Br\u1E47acinm\u0101tratva\u1E41 yad...&quot; - &quot;... [\u0422\u0435\u0440\u043C\u0438\u043D] svar\u016Bpa [\u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435\u2014 \u044D\u0442\u043E \u0442\u043E,] \u0447\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u0437 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0435\u0442\u043B\u0438, \u0438\u043B\u0438 \u043E\u043A\u043E\u0432\u044B...&quot;.</p></li></ol><p>\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u0442\u0435\u0440\u043C\u0438\u043D &quot;avalokana&quot;, \u0445\u043E\u0442\u044F \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435, \u0432\u0438\u0434\u0435\u043D\u0438\u0435 \u0438 \u0442.\u043F..&quot;, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E K\u1E63emar\u0101ja \u0435\u0441\u0442\u044C &quot; \u0906\u0924\u094D\u092E\u0924\u094D\u0935\u0947\u0928\u093E\u092D\u093F\u092E\u0928\u0928 &quot; - &quot;\u0101tmatven\u0101bhimanana&quot; - &quot;\u0434\u0443\u043C\u0430\u0442\u044C, \u0447\u0442\u043E [\u0447\u0442\u043E-\u0442\u043E] \u0435\u0441\u0442\u044C \u0432\u044B&quot;. \u041E\u0442\u0441\u044E\u0434\u0430 \u043C\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 &quot;avalokana&quot; \u043A\u0430\u043A &quot;\u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435&quot;. \u042D\u0442\u043E \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u043F\u043E\u043C\u043E\u0436\u0435\u0442 \u043B\u044E\u0434\u044F\u043C \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E \u0442\u0435\u043C, \u043A\u0442\u043E \u0438\u0437\u0443\u0447\u0430\u0435\u0442 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442 \u0433\u043B\u0443\u0431\u043E\u043A\u043E. \u0422\u0435\u043A\u0441\u0442 Svacchandatantra \u043F\u043E\u043B\u043E\u043D &quot;\u043A\u0430\u0436\u0443\u0449\u0438\u0445\u0441\u044F&quot; \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u0439, \u043A\u0430\u043A \u0431\u0443\u0434\u0442\u043E \u0430\u0432\u0442\u043E\u0440 \u0432\u0440\u0435\u043C\u0435\u043D\u0430\u043C\u0438 \u043D\u0435 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043B \u0441\u0442\u0440\u043E\u0433\u0438\u043C \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u043D\u0430\u0443\u0447\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 K\u1E63emar\u0101ja (\u0442.\u0435. Svacchandoddyota), \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u043A \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0437\u043D\u0430\u0435\u0442 \u0442\u0430\u0439\u043D\u044B\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u043C\u043D\u043E\u0433\u0438\u0445 \u043D\u0435\u044F\u0441\u043D\u044B\u0445 \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u0432 \u0438 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0439, \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0449\u0438\u0445\u0441\u044F \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C Svacchandatantra. \u041A\u0441\u0442\u0430\u0442\u0438, Svacchandoddyota \u2014\u044D\u0442\u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043D\u0430 Svacchandatantra. \u0411\u044B\u043B \u0434\u0440\u0443\u0433\u043E\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0442\u043E\u0440, \u043D\u043E \u043E\u043D \u043F\u043E\u0442\u0435\u0440\u044F\u043B\u0441\u044F \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u0432\u0435\u043A\u043E\u0432.</p><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u043E\u0431\u0440\u0430\u0449\u0430\u044F\u0441\u044C \u0441\u0435\u0439\u0447\u0430\u0441 \u043A \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u043C \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C: Svacchandatantra \u2014 \u044D\u0442\u043E \u044F\u0440\u043A\u0438\u0439 \u043F\u0440\u0438\u043C\u0435\u0440 \u0442\u0435\u043E\u0440\u0438\u0438 \u043F\u0440\u043E\u0442\u0438\u0432 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438, \u044F \u0438\u043C\u0435\u044E \u0432 \u0432\u0438\u0434\u0443, \u0447\u0442\u043E \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0432\u044B\u0443\u0447\u0438\u0442\u044C \u0432\u0441\u0435 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u0430, \u043D\u043E \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0435\u0442\u0435\u0441\u044C \u0441 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C\u0438 &quot;\u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C\u0438&quot; \u0442\u0435\u043A\u0441\u0442\u0430\u043C\u0438, \u0432\u044B \u043D\u0435 \u043C\u043E\u0436\u0435\u0442\u0435 \u0438\u0445 \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438. \u041F\u043E\u0447\u0435\u043C\u0443? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u0438 \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u044E\u0442 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0442\u0435\u043E\u0440\u0438\u0438, \u0431\u0443\u0434\u044C \u0442\u043E \u0438\u0437-\u0437\u0430 \u043E\u0448\u0438\u0431\u043E\u043A \u0432 \u0442\u0440\u0430\u043D\u0441\u043A\u0440\u0438\u043F\u0446\u0438\u0438, \u0438\u043B\u0438 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0430\u0432\u0442\u043E\u0440 \u0437\u0430\u0448\u0438\u0444\u0440\u043E\u0432\u0430\u043B \u0442\u0430\u0439\u043D\u044B\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u0441\u0442\u0440\u0430\u043D\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0438\u043B\u0438 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0441\u0442\u0438\u043B\u044C \u043E\u0447\u0435\u043D\u044C \u0441\u0442\u0430\u0440\u044B\u0439, \u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u044C \u0440\u0438\u0442\u043C\u0430 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043B\u0430 \u0442\u0432\u0438\u0441\u0442\u0430 \u0432 \u043C\u0430\u043D\u0435\u0440\u0435 \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043D\u0435 \u043B\u044E\u0431\u043B\u044E \u043E\u0431\u0443\u0447\u0430\u0442\u044C \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0443 \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0438\u043C\u0435\u0440\u044B, \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0435 \u044D\u0442\u0438\u043C: &quot;\u042D\u0442\u043E \u2014 \u043A\u043E\u0440\u043E\u0431\u043A\u0430, \u0430 \u044D\u0442\u043E \u2014 \u043C\u043E\u0439 \u043A\u043E\u0442&quot; \u0438 \u0442.\u043F., \u043A\u0430\u043A \u0435\u0441\u043B\u0438 \u0431\u044B \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442 \u0431\u044B\u043B \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u0438\u043C \u0438\u043B\u0438 \u0438\u0441\u043F\u0430\u043D\u0441\u043A\u0438\u043C \u044F\u0437\u044B\u043A\u043E\u043C. \u042D\u0442\u043E \u0438\u0437\u043B\u0438\u0448\u043D\u0435, \u0445\u043E\u0442\u044F, \u043F\u043E-\u0432\u0438\u0434\u0438\u043C\u043E\u043C\u0443, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E, \u043A\u043E\u0433\u0434\u0430 \u0442\u0430\u043A \u043E\u0431\u0443\u0447\u0430\u044E\u0442 \u043D\u043E\u0432\u0438\u0447\u043A\u043E\u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0443, \u0447\u0442\u043E \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0438\u0445 \u0434\u0443\u043C\u0430\u0442\u044C, \u0431\u0443\u0434\u0442\u043E \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0435 \u0442\u0435\u043A\u0441\u0442\u044B \u0432\u0441\u0435\u0433\u0434\u0430 \u0431\u0443\u0434\u0443\u0442 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C \u043B\u043E\u0433\u0438\u0447\u043D\u044B\u043C \u0438 \u043F\u0440\u0438\u044F\u0442\u043D\u044B\u043C \u0448\u0430\u0431\u043B\u043E\u043D\u0430\u043C. \u042D\u0442\u043E \u043E\u0441\u043D\u043E\u0432\u043D\u0430\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430, \u043F\u043E \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043C\u043D\u043E\u0433\u0438\u0435 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0435 \u0443\u0447\u0435\u043D\u0438\u043A\u0438 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430 \u043D\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u044C \u043F\u043E\u043D\u0430\u0447\u0430\u043B\u0443 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0435 \u0442\u0435\u043A\u0441\u0442\u044B &quot;\u0441\u0432\u043E\u0438\u043C\u0438 \u0441\u0438\u043B\u0430\u043C\u0438&quot;, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0432\u0441\u0435 \u0438\u0445 \u043C\u0430\u0441\u0441\u0438\u0432\u043D\u044B\u0435 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0437\u043D\u0430\u043D\u0438\u044F.</p><ol start="5"><li>\u0414\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432: \u0442\u0435\u043A\u0441\u0442 &quot;S\u0101rvaj\xF1y\u0101digu\u1E47\u0101 ye&#39;rth\u0101 vy\u0101pak\u0101nbh\u0101vayedyad\u0101&quot; \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u0441\u0442\u0440\u0430\u043D\u043D\u043E, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0442\u0430\u043C \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0441\u043B\u043E\u0432\u043E &quot;t\u0101n&quot; [\u0442\u0435 - \u0410\u043A\u043A\u0443\u0437\u0430\u0442\u0438\u0432 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430 \u043E\u0442 tad (\u043C.\u0440.)]. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u0430\u044F \u0441\u0432\u044F\u0437\u044C \u043C\u0435\u0436\u0434\u0443 &quot;S\u0101rvaj\xF1y\u0101digu\u1E47\u0101 ye&#39;rth\u0101\u1E25&quot; \u0438 &quot;vy\u0101pak\u0101n&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u043F\u0435\u0440\u0432\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u041D\u043E\u043C\u0438\u043D\u0430\u0442\u0438\u0432 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430, \u0430 \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u043C \u2014 \u0410\u043A\u043A\u0443\u0437\u0430\u0442\u0438\u0432 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430. \u0422\u0435\u043F\u0435\u0440\u044C, \u0434\u043B\u044F \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u043C\u0435\u0440\u0442\u043D\u044B\u0445 (\u0445\u0430-\u0445\u0430!): \u043C\u043D\u0435 \u043D\u0430\u0434\u043E \u0447\u0435\u0442\u043A\u043E \u0443\u043A\u0430\u0437\u0430\u0442\u044C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043C\u043E\u043C\u0435\u043D\u0442\u044B, \u0447\u0442\u043E\u0431\u044B \u0432\u044B \u043F\u043E\u043D\u044F\u043B\u0438, \u043F\u043E\u0447\u0435\u043C\u0443 \u0438\u043C\u0435\u043D\u043D\u043E \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0441\u0442\u0440\u043E\u0444\u0443 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C. \u0427\u0442\u043E\u0431\u044B \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0432\u0441\u0435 \u044D\u0442\u043E, \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0443 \u0432\u0435\u0441\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 K\u1E63emar\u0101ja \u043D\u0430 \u0434\u0432\u0435 \u0441\u0442\u0440\u043E\u043A\u0438 &quot;S\u0101rvaj\xF1y\u0101digu\u1E47\u0101 ye&#39;rth\u0101 vy\u0101pak\u0101nbh\u0101vayedyad\u0101| \u015Aivavy\u0101ptirbhavatye\u1E63\u0101 caitanye hetur\u016Bpi\u1E47\u012B||&quot; \u0432 \u0435\u0433\u043E Svacchandoddyota:</li></ol><blockquote><p>&quot; \u092F\u0947 \u0935\u0915\u094D\u0937\u094D\u092F\u092E\u093E\u0923\u093E\u0903 \u0938\u0930\u094D\u0935\u091C\u094D\u091E\u0924\u094D\u0935\u0938\u0930\u094D\u0935\u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u093E\u0926\u093F\u0917\u0941\u0923\u093E \u0927\u0930\u094D\u092E\u093E\u0903 \u092A\u0930\u092E\u094B\u092A\u093E\u0926\u0947\u092F\u0924\u094D\u0935\u0947\u0928\u093E\u0930\u094D\u0925\u094D\u092F\u092E\u093E\u0928\u0924\u094D\u0935\u093E\u0926\u0930\u094D\u0925\u093E\u0938\u094D\u0924\u093E\u0928\u094D\u0935\u094D\u092F\u093E\u092A\u0915\u093E\u0928\u093F\u0924\u093F \u0905\u0936\u0947\u0937\u092E\u0928\u094D\u0924\u0930\u092D\u0947\u0926\u0947\u0928 \u0915\u094D\u0930\u094B\u0921\u0940\u0915\u0941\u0930\u094D\u0935\u0924\u094B \u092F\u0926\u093E \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u093F \u092D\u093E\u0935\u092F\u0947\u0924\u094D\u0924\u0926\u093E \u0924\u0926\u094D\u092D\u093E\u0935\u0928\u093E\u092A\u0930\u093F\u0928\u093F\u0937\u094D\u092A\u0924\u094D\u0924\u093F\u0930\u093E\u0924\u094D\u092E\u0928\u0903 \u0936\u093F\u0935\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u093F\u0903 \u0938\u093E \u091A \u092D\u093E\u0935\u0915\u0947 \u091A\u0948\u0924\u0928\u094D\u092F\u0947 \u0939\u0947\u0924\u0941\u0930\u0942\u092A\u093F\u0923\u0940 \u092A\u094D\u0930\u092F\u094B\u091C\u093F\u0915\u093E \u0924\u0924\u094D\u092A\u094D\u0930\u0938\u093E\u0926\u093E\u0926\u0947\u0935 \u0936\u0941\u0926\u094D\u0927\u093E\u0924\u094D\u092E\u0928\u0938\u094D\u0924\u0926\u094D\u092D\u093E\u0935\u0928\u093E\u092A\u094D\u0930\u0930\u0942\u0922\u0947\u0903\u0965\u096A\u0969\u096B\u0965 &quot; - &quot;Ye vak\u1E63yam\u0101\u1E47\u0101\u1E25 sarvaj\xF1atvasarvakart\u1E5Btv\u0101digu\u1E47\u0101 dharm\u0101\u1E25 paramop\u0101deyatven\u0101rthyam\u0101natv\u0101darth\u0101st\u0101nvy\u0101pak\u0101niti a\u015Be\u1E63amantarabhedena kro\u1E0D\u012Bkurvato yad\u0101 sv\u0101tmani bh\u0101vayettad\u0101 tadbh\u0101van\u0101parini\u1E63pattir\u0101tmana\u1E25 \u015Bivavy\u0101pti\u1E25 s\u0101 ca bh\u0101vake caitanye hetur\u016Bpi\u1E47\u012B prayojik\u0101 tatpras\u0101d\u0101deva \u015Buddh\u0101tmanastadbh\u0101van\u0101prar\u016B\u1E0Dhe\u1E25||435||&quot; - &quot;artha-s --\u0436\u0435\u043B\u0430\u0435\u043C\u044B\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B--, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u0443\u0434\u0443\u0442 \u0438\u0437\u0443\u0447\u0430\u0442\u044C\u0441\u044F \u043F\u043E\u0437\u0436\u0435, \u2014 \u044D\u0442\u043E \u0442\u0435, \u0447\u044C\u0438\u043C\u0438 gu\u1E47a, \u0438\u043B\u0438 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430\u043C\u0438 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0438 \u0442.\u043F., \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u0443\u043A\u0430\u0437\u0430\u043D\u044B \u043A\u0430\u043A \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u0435\u0439\u0448\u0438\u0435. \u041A\u043E\u0433\u0434\u0430 [\u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B] \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442, \u0432 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435 --\u0442.\u0435. \u0432\u043D\u0443\u0442\u0440\u0438 \u0441\u0435\u0431\u044F--, \u0442\u0435 [artha-s], \u043A\u0430\u043A &#39;\u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0435 [\u0432\u0441\u0435 \u0441\u0443\u0449\u0435\u0435], \u0442.\u0435. \u043A\u0430\u043A \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u0435 \u0432\u0441\u0435 \u0447\u0435\u0440\u0435\u0437 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u043D\u0435\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0442\u043E\u0433\u0434\u0430 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E \u0435\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F [\u0435\u0441\u0442\u044C] \u0435\u0433\u043E \u015Aivavy\u0101pti [\u0438\u043B\u0438 \u0441\u043B\u0438\u044F\u043D\u0438\u0435 \u0441 \u015Aiva, \u0412\u044B\u0441\u0448\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C]. \u042D\u0442\u043E [\u015Aivavy\u0101pti] \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439, \u0438\u043B\u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0434\u043B\u044F \u0441\u0442\u0438\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F Caitanya --\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- \u0432 \u0447\u0438\u0441\u0442\u043E\u043C \u0443\u043C\u0435 \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 \u044D\u0442\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043B\u0438\u0448\u044C \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438&quot;.</p></blockquote><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043A\u043E\u0440\u043E\u0442\u043A\u043E\u0435 \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u0435, \u0447\u0442\u043E \u0441\u043A\u0430\u0437\u0430\u043B \u043C\u0443\u0434\u0440\u0435\u0446. \u0425\u043E\u0442\u044F \u0432\u043D\u0430\u0447\u0430\u043B\u0435, \u0432 \u0100tmavy\u0101pti, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u043B \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443, \u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E J\xF1\u0101na, \u0438\u043B\u0438 \u0417\u043D\u0430\u043D\u0438\u0435, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0435 Kriy\u0101, \u0438\u043B\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E, artha-s, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0438 \u043F\u0440., \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0442\u0441\u044F \u043A\u0430\u043A \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0435, \u0438\u043B\u0438 \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0438\u0435 \u0432 \u0441\u0435\u0431\u044F \u0432\u0441\u0435 \u0441\u0443\u0449\u0435\u0435 \u0447\u0435\u0440\u0435\u0437 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C. \u041A\u043E\u0440\u043E\u0447\u0435, \u0441\u0438\u043B\u044B \u0432\u0441\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F, \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0438 \u0442.\u043F. \u043F\u0440\u043E\u0435\u0446\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043D\u0430 \u0432\u0441\u0435, \u0438 \u0432\u0435\u0441\u044C \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u0443 Yog\u012B \u0432\u0438\u0434\u0435\u043D\u0438\u0435\u043C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0432\u0441\u0435\u0445 \u0432\u0435\u0449\u0435\u0439. \u0421\u0430\u043C\u043E\u0441\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043E\u0442 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E, \u0430 \u043D\u0430\u043E\u0431\u043E\u0440\u043E\u0442, Yog\u012B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442, \u0447\u0442\u043E \u0435\u0433\u043E \u0421\u0430\u043C\u043E\u0441\u0442\u044C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C (\u015Aiva) \u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0432\u0441\u0435\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439.</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0438\u043C\u0435\u044E\u0442\u0441\u044F \u044D\u0442\u0430\u043F\u044B. \u041F\u0435\u0440\u0432\u044B\u043C \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u043E\u043C \u015Aivavy\u0101pti \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Kramamudr\u0101. \u0412 \u044D\u0442\u043E\u0439 Mudr\u0101 (\u041F\u0435\u0447\u0430\u0442\u0438) \u0435\u0441\u0442\u044C \u043F\u043E\u0440\u044F\u0434\u043E\u043A \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C (krama). \u041A\u0430\u043A (\u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442)? Yog\u012B \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u043D\u0438\u044F \u0438 \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u043D\u0438\u044F \u0433\u043B\u0430\u0437. \u041A\u043E\u0433\u0434\u0430 \u0433\u043B\u0430\u0437\u0430 \u0437\u0430\u043A\u0440\u044B\u0442\u044B, \u043E\u043D \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u0430 \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044B, \u043E\u043D \u0432\u0438\u0434\u0438\u0442 \u0432\u0441\u044E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u043D\u0443\u044E \u044D\u0442\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E. \u042D\u0442\u0430 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C (\u0442.\u0435. \u043D\u0438\u043A\u0430\u043A\u043E\u0435 \u044D\u0433\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0438\u0442\u044C \u0442\u0430\u043A\u043E\u0435). \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 Kramamudr\u0101 \u0438 \u0432\u044B\u0442\u0435\u043A\u0430\u044E\u0449\u0435\u0435 \u0438\u0437 \u044D\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0447\u0442\u043E \u0432\u0441\u0435 \u0435\u0441\u0442\u044C \u0412\u044B\u0441\u0448\u0435\u0435 \u042F, \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435\u043C, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0422\u0440\u0438\u043A\u0435. \u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u043E\u0433\u0434\u0430, \u043A\u043E\u0433\u0434\u0430 Yog\u012B \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0443\u044E \u0421\u0432\u043E\u0431\u043E\u0434\u0443 (Sv\u0101tantrya, \u0438\u043B\u0438 Sv\u0101cchandya) \u0413\u043E\u0441\u043F\u043E\u0434\u0430. \u0418 \u0432 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435 \u015Aivavy\u0101pti \u0435\u0441\u0442\u044C &quot; \u092D\u093E\u0935\u0915\u0947 \u091A\u0948\u0924\u0928\u094D\u092F\u0947 \u0939\u0947\u0924\u0941\u0930\u0942\u092A\u093F\u0923\u0940 \u092A\u094D\u0930\u092F\u094B\u091C\u093F\u0915\u093E &quot; - &quot;bh\u0101vake caitanye hetur\u016Bpi\u1E47\u012B prayojik\u0101&quot;, \u0442.\u0435. &quot;\u043F\u0440\u0438\u0447\u0438\u043D\u0430, \u0438\u043B\u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E \u0434\u043B\u044F \u0441\u0442\u0438\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F Caitanya --\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F--&quot; . \u0420\u0430\u0437\u0432\u0438\u0442\u0438\u0435, \u0438\u043B\u0438 \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044F \u0432\u043E \u0447\u0442\u043E? \u0412 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0443\u044E \u0421\u0432\u043E\u0431\u043E\u0434\u0443! \u0412 \u043E\u0431\u0449\u0435\u043C, \u015Aivavy\u0101pti \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u043A \u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u043C\u0443 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044E, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E. \u0418 \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0447\u0438\u0441\u0442\u043E\u043C \u0443\u043C\u0435 \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 \u0442\u0430\u043A\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F. \u0418 \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u044D\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438, \u0438 \u043D\u0438\u043A\u0430\u043A \u0438\u043D\u0430\u0447\u0435 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0447\u0435\u0440\u0435\u0437 \u0443\u0441\u0438\u043B\u0438\u044F). \u0417\u0434\u0435\u0441\u044C \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0431\u043E\u043B\u044C\u0448\u0435 \u0442\u0430\u0439\u043D, \u043D\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043C\u043D\u0435, \u0447\u0442\u043E \u044D\u0442\u043E\u0433\u043E \u0431\u044B\u043B\u043E \u0431\u043E\u043B\u044C\u0448\u0435, \u0447\u0435\u043C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E.</p></div>',1),n=[p];function y(i,r,v,u,s,d){return e(),t("div",null,n)}var k=a(o,[["render",y]]);export{c as __pageData,k as default};
